const rows = $input.all().map(x => x.json || {});

const normalizeName = (r) => String(r.name || r.fileName || r.filename || r.base || '').trim();
const normalizePath = (r) => String(r.path || r.fullPath || r.filePath || '').trim();
const toTime = (r) => {
  const v = r.modifiedAt || r.lastModified || r.modifyTime || r.mtime || r.updatedAt || null;
  const d = v ? new Date(v) : null;
  return d && !Number.isNaN(d.getTime()) ? d.getTime() : 0;
};

const isFile = (r) => {
  const t = String(r.type || r.fileType || '').toLowerCase();
  const isDir = Boolean(r.isDirectory) || t === 'd' || t === 'directory';
  return !isDir;
};

const candidates = rows
  .map(r => ({
    name: normalizeName(r),
    path: normalizePath(r),
    t: toTime(r),
    raw: r,
  }))
  .filter(x => isFile(x.raw))
  .filter(x => /\.(xlsx|csv|txt)$/i.test(x.name))
  .filter(x => !/\/procesados\//i.test(x.path) && !/^procesados\//i.test(x.name));

if (candidates.length === 0) {
  return [{
    json: {
      is_target_file: false,
      file_name: null,
      file_ext: null,
      file_path: null,
      reason: 'No existe archivo .xlsx, .csv o .txt en ./public_html/BANCO_SOLIDARIO para procesar.',
    },
  }];
}

candidates.sort((a, b) => b.t - a.t || b.name.localeCompare(a.name));
const selected = candidates[0];
const ext = selected.name.split('.').pop().toLowerCase();

return [{
  json: {
    is_target_file: true,
    file_name: selected.name,
    file_ext: ext,
    file_path: selected.path || ('./public_html/BANCO_SOLIDARIO/' + selected.name),
    processed_path: './public_html/BANCO_SOLIDARIO/procesados/' + selected.name,
  },
}];

const trigger = $items('Validar Nombre Archivo', 0, 0)[0]?.json || {};
const fileName = String(trigger.file_name || 'archivo_desconocido');

const SUPABASE_URL = $env.SUPABASE_URL || 'https://suokpkpzpfvadwemxzfa.supabase.co';
const SUPABASE_ANON_KEY =
  $env.SUPABASE_ANON_KEY ||
  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InN1b2twa3B6cGZ2YWR3ZW14emZhIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTkyNjM0ODgsImV4cCI6MjA3NDgzOTQ4OH0.bSMXRoVj_5vjIftDV1VcjauQQhYhK5AL7fz3VFln72A';

const all = $input.all();

if (!Array.isArray(all) || all.length === 0) {
  return [{ json: { status: 'error', file_name: fileName, total_rows: 0, valid_rows: 0, upsert_ok: 0, failed_rows: 1, failed_details: [{ row: '-', num_operacion: null, reason: 'El archivo no tiene filas o no se pudo leer.' }], failed_details_text: '- Fila - | num_operacion: - | motivo: El archivo no tiene filas o no se pudo leer.' } }];
}

const COLUMN_MAP = {
    numerooperacion: 'num_operacion',
    identificacion: 'cedula',
    nombres: 'nombre',
    apellidos: 'apellido',
    telefono1: 'telefono1',
    telefono2: 'telefono2',
    telefono3: 'telefono3',
    telefono4: 'telefono4',
    telefono5: 'telefono5',
    telefono6: 'telefono6',
    valorcompletocuota: 'monto',
    fechaproximovencimiento: 'fecha_vencimiento',
    diasvencido: 'dias_retraso',
    dias_retraso: 'dias_retraso',
    producto: 'producto',
    num_operacion: 'num_operacion',
    numero_operacion: 'num_operacion',
    cedula: 'cedula',
    nombre: 'nombre',
    apellido: 'apellido',
    monto: 'monto',
    fecha_vencimiento: 'fecha_vencimiento',
};

const normalizeHeader = (k) => String(k || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\s+/g, '').toLowerCase().trim();
const toText = (v) => { if (v === null || v === undefined) return null; const t = String(v).trim(); return t === '' ? null : t; };
const toNumber = (v) => { if (v === null || v === undefined || String(v).trim() === '') return null; if (typeof v === 'number') return Number.isFinite(v) ? v : null; const n = Number(String(v).replace(/\s/g,'').replace(/,/g,'.')); return Number.isFinite(n) ? n : null; };
const toDate = (v) => {
  if (v === null || v === undefined || String(v).trim() === '') return null;
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  if (/^\d{2}[-/]\d{2}[-/]\d{4}$/.test(s)) { const [d,m,y] = s.split(/[-/]/); return y + '-' + m + '-' + d; }
  const d = new Date(s);
  return Number.isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10);
};

const nowIso = new Date().toISOString();
const validRows = [];
const failed = [];

for (let i = 0; i < all.length; i++) {
  const rawRow = all[i].json || {};
  const normalizedRow = {};
  for (const [k, v] of Object.entries(rawRow)) {
    const norm = normalizeHeader(k);
    const sqlCol = COLUMN_MAP[norm];
    if (sqlCol) normalizedRow[sqlCol] = v;
  }

  const rowNumber = i + 2;
  const errors = [];
  const numOperacion = toText(normalizedRow.num_operacion);

  if (!numOperacion) errors.push('num_operacion requerido');

  const record = {
    num_operacion: numOperacion,
    cedula: toText(normalizedRow.cedula),
    nombre: toText(normalizedRow.nombre),
    apellido: toText(normalizedRow.apellido),
    telefono1: toText(normalizedRow.telefono1),
    telefono2: toText(normalizedRow.telefono2),
    telefono3: toText(normalizedRow.telefono3),
    telefono4: toText(normalizedRow.telefono4),
    telefono5: toText(normalizedRow.telefono5),
    telefono6: toText(normalizedRow.telefono6),
    monto: toNumber(normalizedRow.monto),
    fecha_vencimiento: toDate(normalizedRow.fecha_vencimiento),
    producto: toText(normalizedRow.producto),
    dias_retraso: toText(normalizedRow.dias_retraso),
    updated_at: nowIso,
    estado_flujo: 'PENDIENTE',
  };

  if (errors.length > 0) {
    failed.push({ row: rowNumber, num_operacion: numOperacion, reason: errors.join('; ') });
    continue;
  }
  validRows.push(record);
}

if (failed.length > 0) {
  const failedText = failed.slice(0, 200).map((f) => '- Fila ' + f.row + ' | num_operacion: ' + (f.num_operacion || '-') + ' | motivo: ' + f.reason).join('\n');
  return [{ json: { status: 'error', file_name: fileName, total_rows: all.length, valid_rows: validRows.length, failed_rows: failed.length, failed_details_text: failedText } }];
}

return [{
  json: {
    status: 'ok', 
    file_name: fileName,
    total_rows: all.length,
    valid_rows: validRows.length,
    payload: validRows,
    supabase_url: SUPABASE_URL,
    supabase_key: SUPABASE_ANON_KEY,
    file_path: trigger.file_path,
    processed_path: trigger.processed_path
  }
}];

const binaryData = await $input.item.binary.data;
const text = Buffer.from(binaryData.data, 'base64').toString('utf8');

const lines = text.split(/\r?\n/).filter(l => l.trim() !== '');
if (lines.length < 2) return [];

const detectDelimiter = (header) => {
  if (header.includes('\t')) return '\t';
  if (header.includes(';')) return ';';
  return ',';
};

const delimiter = detectDelimiter(lines[0]);
const headers = lines[0].split(delimiter).map(h => h.replace(/^\uFEFF/, '').trim());

const rows = [];
for (let i = 1; i < lines.length; i++) {
  const values = lines[i].split(delimiter);
  const row = {};
  headers.forEach((h, idx) => {
    row[h] = values[idx] || '';
  });
  rows.push({ json: row });
}

return rows;
